window.__QUIZ_DATA__=[{"id":"objective>Agricultural Science>2004>1","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"BASIC CONCEPTS : MEANING AND DIFFERENCES BETWEEN SUBSISTENCE AND COMMERCIAL AGRICULTURE","question":"One factor which differentiate a subsistence from a commercial farmer is that the former produces","images":[],"options":{"A":"For the benefit of the community","B":"only one type of crop","C":"for the benefit of his family","D":"raw materials for agro-based industries"},"answer":"C","explanation":"In subsistence agriculture,farmers cultivates crops to feed himself and his family while commercial agriculture deals mainly for sale or export.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2004>2","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"AGRICULTURAL ECOLOGY : FACTORS AFFECTING LAND AVAILABILITY FOR AGRICULTURAL PURPOSE","question":"Which of the following land tenure systems encourages the establishment of permanent crops?","images":[],"options":{"A":"Freehold system","B":"tenancy","C":"leashold system","D":"pledging"},"answer":"A","explanation":"Freehold system is a type of land tenure system in which a farmer buys a piece of land for agricultural purposes. Perennial crops can be grown on the land.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>3","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"AGRICULTURAL ECOLOGY : FACTORS AFFECTING LAND AVAILABILITY FOR AGRICULTURAL PURPOSE","question":"The land tenure system thta result in fragementation of land is","images":[],"options":{"A":"freehold","B":"government tenancy","C":"inheritance","D":"leasehold"},"answer":"C","explanation":"This is a type of land tenure in which land is inherited from one's parent or from one generation to another. The land can be improved by way of fertilizer application in order to maintain its fertility. It leads to excessive land fragmentation which makes the land very difficult and uneconomically to work.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>4","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"AGRICULTURAL ECOLOGY : FACTORS AFFECTING LAND AVAILABILITY FOR AGRICULTURAL PURPOSE","question":"The use of land for agriculture is not influenced by","images":[],"options":{"A":"labour","B":"climate","C":"topography","D":"population"},"answer":"D","explanation":"While population can affect the demand for agricultural products, it does not directly influence the suitability of land for agricultural use.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2004>5","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"AGRICULTURAL ECOLOGY : ROCK FORMATION","question":"Igneous rock formed within the crust are called","images":[],"options":{"A":"guartzite","B":"volcanic","C":"plutonic","D":"stratified"},"answer":"C","explanation":"Plutonic rocks form from magma that cools and solidifies within the crust of the Earth, as opposed to volcanic rocks, which form from lava that cools on the Earth's surface.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>6","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"AGRICULTURAL ECOLOGY : ROCK FORMATION","question":"The chemical reaction in the rock represented by KAISiO3O8 + H2O \u2192HA1SiO8 + KOH is an example of","images":[],"options":{"A":"hydrolysis","B":"hydration","C":"oxidation","D":"carbonation"},"answer":"A","explanation":"KAlSiO 3O 8 + H 2O \u2192 HAlSi 3O 8 + KOH  (Microcline)              (Water)       (Acid Silicate)  Hydrolysis is a decomposition reaction in which silicate minerals are broke down. Water molecule is split into H+ and OH - ions  H 2O \u2192H + OH+","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2004>7","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL","question":"clay particles are able to attracts action in te soil because they","images":[],"options":{"A":"they are positively charged","B":"have excess negative charges","C":"are sticky","D":"can be moulded"},"answer":"B","explanation":"Clay particles are fine,powdery and smooth when dry.The particles are sticky and mouldy when wet. They have excess negative charges. The particles are tightly bound together with little pore (air) spaces.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>8","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL","question":"What is the percentage  porosity of a soil sample whose volume is 250cm3 when the volume of air is 200cm3?","images":[],"options":{"A":"20","B":"25","C":"50","D":"80"},"answer":"A","explanation":"Parameters given:  Volume of soil = 250cm 3  Volume of air =200cm 3  Percentage porosity = Volume of space occupied by the soil/Volume of soil  Therefore,%porosity = (50cm 3/250cm 3 \u22c6 100 = 20%","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>9","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL","question":"The most important soil micro-organism causing decay and nutrient recycling are","images":[],"options":{"A":"bacterial and fungi","B":"fungi and algae","C":"Algae and actinomycetes","D":"bacterial and algae"},"answer":"A","explanation":"Bacteria and fungi are micro organisms which causes diseases in farm animal. They cause decay and nutrient recycling in nutrioent cycle. Example of nutrients like nitrogen,carbon and water in nature.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2004>10","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL","question":"Which of the following soil water is tightly held to the surface of the soil particles","images":[],"options":{"A":"hygroscopic water","B":"gravitational water","C":"capillary water","D":"superfluous water"},"answer":"A","explanation":"Hygroscopic water is the type of soil water that is tightly held to the surface of the soil particles. It is held by adsorption and is not available to plants because it is held too tightly for the roots to absorb. It is also not affected by gravity.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>11","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"Which of the following process will not lead to the loss of nutrient from the soil?","images":[],"options":{"A":"erosion","B":"mulching","C":"harvesting","D":"leaching"},"answer":"B","explanation":"Mulching does not lead to the loss of nutrients from the soil. Instead, it helps to conserve soil moisture, reduce erosion, and can contribute to the health of the soil by decomposing into organic matter. The other options, erosion, harvesting, and leaching, all lead to nutrient loss from the soil.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>12","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"A disadvantages of using organic manure on the soil is that","images":[],"options":{"A":"it decreases the potassium content of the soil","B":"disease spread fast","C":"it increases the humus content of the soil","D":"it reduces the rate of soil water evaporation"},"answer":"B","explanation":"Organic manure represents the decomposition of plants and animal. It is about 5% of the total volume. Its disadvantages is trhat its spread fast that is its spread diseases faster in the soil.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>13","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"Leguminous cover crop do not","images":[],"options":{"A":"bind the soil particles together through their roots","B":"increase the nitrogen content of soil","C":"aid in improving the soil organic matter content","D":"reduce the soil microbial population"},"answer":"D","explanation":"Leguminous cover crops are crops that are rich sources of protein, e.g cowpea,soya beans, groundnut, lima beans and pigeon pea. They increase the nitogen content of soils, bind the soil particles together through the roots.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>14","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"In the nitrogen  cycle , nitrite is oxidized to nitrate by","images":[],"options":{"A":"nitrobacter","B":"nitrosomonas","C":"azotobacter","D":"rhizobium"},"answer":"A","explanation":"In the nitrogen cycle, nitrite (NO2-) is oxidized to nitrate (NO3-) by the bacteria Nitrobacter. This process is known as nitrification. Nitrosomonas is involved in the first step of nitrification, which is the oxidation of ammonia (NH3) to nitrite. Azotobacter and Rhizobium are nitrogen-fixing bacteria, they convert atmospheric nitrogen (N2) into a form that plants can use.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>15","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"Which of the following will not lead to loss of nitrogen compound from the soil?","images":[],"options":{"A":"crop removal","B":"burning","C":"lodging","D":"leaching"},"answer":"C","explanation":"Lodging refers to the falling over of crops, usually due to wind or heavy rain. This does not lead to a loss of nitrogen compounds from the soil. Nitrogen loss from the soil can occur through crop removal, burning, and leaching. Leaching is the process where nutrients are washed out from the soil by rain or irrigation. Burning can lead to the loss of nitrogen as it can volatilize and escape into the atmosphere. Crop removal can also lead to nitrogen loss as the nutrient is taken up by the plants and removed when the crop is harvested.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>16","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"AGRICULTURAL ECOLOGY : DRAINAGE","question":"Farm drainage does not lead to","images":[],"options":{"A":"improvement in soil structure","B":"improvement of soil temperature","C":"increased soil aeration","D":"reduction of soil alkalinity"},"answer":"D","explanation":"Farm drainage is a process whereby excess water in the soil is removed artificially to promote good farming activities. Farm drainage does not lead to reduction of soil alkalinity but reduce soil alkalinity but reduce soil acidity.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>17","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"AGRICULTURAL ECOLOGY : IRRIGATION","question":"Whic of the following methods of irrigation is best for a farm with an undulating landscape?","images":[],"options":{"A":"sprinkler","B":"flooding","C":"furrow","D":"basin"},"answer":"A","explanation":"Sprinkler is a type of overhead irrigation which spray water from the air and allowed to fall on the ground surface somehow as rainfall,through nozzles under high pressure.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>18","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM POWER","question":"The most unreliable source of farm power is","images":[],"options":{"A":"wind","B":"water","C":"electricity","D":"machines"},"answer":"A","explanation":"Wind power is generated by wind movement. Its use in windmill helps to pump water out of a borehole to a generating set for the production of electricity. Wind is unreliable because it deals with climate and climate is unpredictable.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>19","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM POWER","question":"water power harness and converted into electricity power by","images":[],"options":{"A":"blades","B":"cranes","C":"turbines","D":"hover craft"},"answer":"C","explanation":"Water power is the power derived from water flowing in rivers,streams and dams.Water is used in hydro-electric stations to drive the turbines.It is very cheap,easy to be harnessed,converted to other forms of energy.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>20","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS","question":"A farm implement used for planting grains is the","images":[],"options":{"A":"drill","B":"ridger","C":"harrow","D":"plough"},"answer":"A","explanation":"Drill is a simple farm implement used to plant grains in the farm.Farmers used to prefer drill to plant grains that using machine especially in subsistence agriculture.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2004>21","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS","question":"which part of the tractor is most essential inoperating a mower","images":[],"options":{"A":"steering wheel","B":"top link","C":"power, take-off shaft","D":"stabilizer chains"},"answer":"C","explanation":"The tractor is a powerful and expensive multi-purpose motor vehicle used for lifting or pulling farm implements. It has a power-take-off (P.T.O) shaft used in drawing farm implements like ploughs,harrows,harvesters,planters, e.t.c","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>22","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : PROSPECTS OF AGRICULTURAL MECHANIZATION","question":"farm mechanisation in west Africa is not limited by","images":[],"options":{"A":"A large population of farmers","B":"poverty among the farmers","C":"inadequate infrastructure facilities","D":"seasonality of agricultural production"},"answer":"A","explanation":"Limitations of farm mechanisation in West Africa are affected by factor like economic,technical,lack of maintenance and small farm holdings. Farm mechanization in West Africa is not limited by number of farmers.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>23","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : PROSPECTS OF AGRICULTURAL MECHANIZATION","question":"mechanisation in west Africa is limited by the following except","images":[],"options":{"A":"size of farm holding","B":"technical know-how","C":"capital","D":"labour"},"answer":"D","explanation":"Mechanization in West Africa is limited by size of farm holding,techical know-how, capital and not labour.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>24","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"AGRICULTURAL ECOLOGY : AGRO-ALLIED INDUSTRIES AND RELATIONSHIP BETWEEN AGRICULTURE AND INDUSTRY","question":"A fruit which will not normally be used in the manufacture of jam is","images":[],"options":{"A":"orange","B":"pineapple","C":"garden egg","D":"pawpaw"},"answer":"C","explanation":"Garden egg is a fruit, it is not useful for the production/manufacture of Jam. Fruits that are high in fructose such as orange, pineapple, pawpaw and banana are mainly used for jam production.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2004>25","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"CROP PRODUCTION : CLASSIFICATION OF CROPS","question":"The following  crop are common staple foods in west africa except","images":[],"options":{"A":"coconut","B":"maize","C":"cassava","D":"cowpea"},"answer":"A","explanation":"Staple foods are foods that are grown in West Africa foods like;cassava,millet,rice,maize,cowpea,yam. Coconut is a beverage crop which is used for preparing Ovaltine,Pronto,Bournvita etc.It is not a staple food.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2004>26","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"In cassava farming, rapid growth is promoted at the expense of tuber formation by the application of","images":[],"options":{"A":"potassium fertilizer","B":"nitrogen fertilizer","C":"complete fertilizer","D":"phosphate fertilizer"},"answer":"B","explanation":"Nitrogen fertilizer is a fertilizer application apply four to six weeks after planting cassava.250kg/ha of N.P.K is used for cassava planting.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>27","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"CROP PRODUCTION : CLASSIFICATION OF CROPS","question":"Ananas comosus  is a","images":[],"options":{"A":"Friut crop","B":"oil crop","C":"beverage crop","D":"pasture crop"},"answer":"A","explanation":"Ananas comosus is the scientific name for pineapple, which is a fruit crop. Therefore, the correct answer is 'Fruit crop'.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>28","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : MARKETING OF AGRICULTURAL PRODUCE","question":"The best way to preserve maize grains on a large scale is by","images":[],"options":{"A":"storing under the sun","B":"storing in earthen pots","C":"hanging over fire places","D":"storing silos"},"answer":"D","explanation":"The best way to preserve maize grains on a large scale is by storing in silos. Silos are structures for storing bulk materials. Silos are used in agriculture to store grain or fermented feed known as silage. They are more commonly used for bulk storage of grain, coal, cement, carbon black, woodchips, food products and sawdust.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2004>29","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"AGRICULTURAL ECOLOGY : AGRO-ALLIED INDUSTRIES AND RELATIONSHIP BETWEEN AGRICULTURE AND INDUSTRY","question":"parboiling is a term asssociated with the processing of","images":[],"options":{"A":"cowpea","B":"melon","C":"sorghum","D":"rice"},"answer":"D","explanation":"Parboiling is the process used to reduce the breakage of grains during pounding.It also brings some vitamins to the outer layer of the grains and it also reduces the labour required to remove the husks. The parboiled rice is now sun-dried.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>30","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"Maize is a very important crop because apart from serving as a staple, it","images":[],"options":{"A":"is ploughed into the soil to increase fertility","B":"can be processed into corn flakes","C":"forms the base of most livestock feeds","D":"is used for producing germ oil"},"answer":"C","explanation":"Maize is also called corn.It is a cereal crop which produces grains that can be used as food human beings as well as livestock.Maize forms the base of most livestock.Maize forms the base of most livestock feeds.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>31","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"A variety of oil palm is","images":[],"options":{"A":"trinitario","B":"tenera","C":"crillo","D":"amelonado"},"answer":"B","explanation":"The oil palm belongs to the plant family called palmea or palm family.  The fruit is called a dura,pisifera and tenera.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2004>32","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"ANIMAL PRODUCTION : RANGELAND AND PASTURE MANAGEMENT","question":"Andropogon gayanus is commonly called","images":[],"options":{"A":"guinea grass","B":"elephant grass","C":"gamba grass","D":"spear grass"},"answer":"C","explanation":"Andropogon gayanus is commonly called 'gamba grass'. This is a species of grass native to Africa, but it has been introduced to other parts of the world. It is a tall, perennial grass that is often used for pasture and hay production.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2004>33","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"ANIMAL PRODUCTION : RANGELAND AND PASTURE MANAGEMENT","question":"pasture crop are best used in preparing hay","images":[],"options":{"A":"when they are two weeks old","B":"just before flowering","C":"just after seed maturation","D":"after they have started to dry up"},"answer":"B","explanation":"Pasture crops are best used in preparing hay just before flowering. This is because at this stage, the nutritional content of the plant is at its peak. The plant has not yet used its stored nutrients for the process of flowering and seed production. Therefore, the hay made from such plants will be rich in nutrients.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>34","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"ANIMAL PRODUCTION : RANGELAND AND PASTURE MANAGEMENT","question":"which of the following is not a characteristic of a good pasture?","images":[],"options":{"A":"high quality of grass","B":"provision of balance nutrients","C":"ability to withstand trampling","D":"high stem to leaf ratio"},"answer":"D","explanation":"A high stem to leaf ratio is not a characteristic of a good pasture. In fact, it is the opposite. A good pasture should have a low stem to leaf ratio. This is because the leaves of the plants are more nutritious and palatable to animals than the stems. Therefore, a pasture with a high proportion of leaves to stems will provide better nutrition for grazing animals.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>35","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"CROP PROTECTION : DISEASES OF CROPS","question":"Black pod disease of cocoa is controlled by","images":[],"options":{"A":"fumigation of soil","B":"farm sanitation","C":"application of herbicide","D":"application of fungicide"},"answer":"D","explanation":"Black pod disease of cocoa is controlled by the application of fungicide. Black pod is a fungal disease that affects cocoa plants. Fungicides are chemicals that kill or inhibit the growth of fungi. Therefore, applying fungicide to the cocoa plants will help to control the spread of the black pod disease.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>36","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"CROP PROTECTION : DISEASES OF CROPS","question":"The side effect of chemical control of diseases and pests include the following except","images":[],"options":{"A":"environment pollution","B":"poisoning of livestock and man","C":"destruction of some plant species","D":"increase cost of production"},"answer":"D","explanation":"Chemical control involves the use of chemicals such as fungicides,nematicides,and insecticides to dust or spray plants material in order to prevent or control diseases.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>37","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"CROP PRODUCTION : CROP IMPROVEMENT","question":"plant breeders aim at obtaining the following except","images":[],"options":{"A":"tolerance to climate extremes","B":"resistance of pest","C":"adaptation to pollination","D":"uniformity in the time of maturity"},"answer":"C","explanation":"Plant breeders aim at obtaining tolerance to climate extremes, resistance to pests, and uniformity in the time of maturity. However, adaptation to pollination is not a direct aim of plant breeding. Pollination is a natural process that occurs in plants and is not something that plant breeders aim to adapt or modify.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>38","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"ANIMAL PRODUCTION : TYPES AND CLASSIFICATION OF FARM ANIMALS","question":"Which of the following pairs are breeds of cattle?","images":[],"options":{"A":"muturu and sahel","B":"ouda and white fulani","C":"ndama and keteku","D":"gudali and red sokoto"},"answer":"C","explanation":"Ndama and keteku are breeds of cattle. Ouda is a breed of sheep, Red Sokoto, Sahel are a breed of goat.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2004>39","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"ANIMAL PRODUCTION : TYPES AND CLASSIFICATION OF FARM ANIMALS","question":"A adult female goat is a/an","images":[],"options":{"A":"gilt","B":"heifer","C":"ewe","D":"doe"},"answer":"D","explanation":"An adult female goat is called Doe (Nanny) while the adult male goat is called Buck (Billy).A young or baby goat is called kid.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>40","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL REPRODUCTION","question":"The interval from the beginning of the of one heat period to the beginning of another is known as","images":[],"options":{"A":"gestation period","B":"incubation period","C":"reproductive cycle","D":"oestrus cycle"},"answer":"D","explanation":"Oestrus cycle is the interval from the end of one heat period to the beginning of another.It is also the period of \"heat\" or \"oestrus\" for coiling or making.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>41","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"ANIMAL PRODUCTION : ANATOMY AND PHYSIOLOGY OF FARM ANIMALS","question":"The diagram below represent the digestive tract of a farm animal. use it to answer question.      which of the following animals possesses the illustrated digestive tract?","images":["data:image/jpeg;base64,"],"options":{"A":"sheep","B":"fowl","C":"pig","D":"duck"},"answer":"A","explanation":"Sheep are examples of Ruminant animals that possesses four stomach compartments, they can ruminate and chew the aid.It can digest cellulose and fibres very well.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>42","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"ANIMAL PRODUCTION : ANATOMY AND PHYSIOLOGY OF FARM ANIMALS","question":"The diagram below represent the digestive tract of a farm animal. use it to answer question.    the part where gastric jusice is secreted is labelled?","images":["data:image/jpeg;base64,"],"options":{"A":"I","B":"IV","C":"VI","D":"VIII"},"answer":"B","explanation":"Abomasum is the only glandular stomach. Secretion of gastric juice takes place in the abomasum which is known as the true stomach. It is also the fourth and last compartment of the stomach.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>43","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"ANIMAL PRODUCTION : ANATOMY AND PHYSIOLOGY OF FARM ANIMALS","question":"The diagram below represent the digestive tract of a farm animal. use it to answer question.    water is largely reabsorbed in the part labelled","images":["data:image/jpeg;base64,"],"options":{"A":"V","B":"IV","C":"VI","D":"VIII"},"answer":"A","explanation":"In ruminants, water reabsorption occurs primarily in the omasum(part labelled V) and the large intestine(part labelled I and II makes up the large intestine). The omasum, one of the compartments of the ruminant stomach, has a highly folded structure that allows for significant water absorption. Additionally, the large intestine, including the cecum and colon, further absorbs water and electrolytes from the digesta, helping to maintain the body's fluid balance.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>44","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL REPRODUCTION","question":"The act of partuition in ewe is known as","images":[],"options":{"A":"farrowing","B":"hatching","C":"lambing","D":"calving"},"answer":"C","explanation":"Partuition is the act of giving birth in farm animals. In ewe the acts of partuition is lambing because they give birth in lamb.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2004>45","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL REPRODUCTION","question":"The pregnancy hormone in female animal is","images":[],"options":{"A":"oestrogen","B":"oxytocin","C":"progesterone","D":"relaxin"},"answer":"C","explanation":"Progesterone(pregnancy hormone) ensures the development of uterus and implantation of the fertilised ovum. It inhibits oestrus that is. It prevents the ripening of more follicles).","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2004>46","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"Which of the following management pratices is specified to dairy farming?","images":[],"options":{"A":"milking","B":"detricking","C":"castration","D":"deworming"},"answer":"A","explanation":"Dairy farming is a system of farming in which animal are reared mainly to produce milk. The milk are exported and also imported for foreign exchange.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2004>47","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"which of the following is the main reason for not keeping birds meant for commercial egg production under the extensive system of management ? birds.","images":[],"options":{"A":"are exposed o attack byy predators","B":"waste a lot of productive energy roaming about","C":"are exposed to sufficient green forage","D":"are exposed to theft"},"answer":"B","explanation":"Extensive system is a type of system in which domestic fowls are allowed to roam about in search of food and water. There are no proper housing, care and feeding for these birds.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>48","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"Newcastle disease is caused by","images":[],"options":{"A":"virus","B":"bacterium","C":"protozoan","D":"fungus"},"answer":"A","explanation":"Newcastle disease is caused by virus and affects domestic fowls, turkey, ducks, goose and guinea fowls. It is transmitted through contaminated feed, water, breeds and litter and controlled by vaccination, proper sanitation and disinfection.Poultry building.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>49","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"A viral disease of ruminants in which the affected animals shows symptoms of high fever and blood stained diarrhoea is likely to be","images":[],"options":{"A":"pleuropneumonia","B":"rinderpest","C":"gastroenteritis","D":"babesiosis"},"answer":"B","explanation":"Rinderpest disease or cattle plaque is affected by animals like cattle,sheep and goat and caused by virus. Its symptoms include;high fever,weakness,difficult breaking, blood stained diarrhoea, high mortality and loss of appetite and weight.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>50","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"The following are practical measure of controlling trypanosomiasis except","images":[],"options":{"A":"spraying against the vector","B":"modification of vector habitat","C":"use of drug on diseased livestock","D":"vaccinating against trypanosmes"},"answer":"D","explanation":"Trypanosomiasis is a protozoa diseases.It is caused by a protozoan called trypanosoma spp, e.g hypanosoma vevase. In controls include  cleaning of bush around the farm, spraying with insecticides to kill vector(tsetsefly), Isolated affected animals.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>51","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"ANIMAL PRODUCTION : AQUACULTURE","question":"The following factors are neccessary for siting fish ponds except","images":[],"options":{"A":"spraying against the vector","B":"modification of vector's habitat","C":"use of drug on disease livestock","D":"vaccinating against trypanosomes."},"answer":"D","explanation":"The factors or conditions necessary for siting a fish pond includes;Adequate water supply, soil in the area,vegetation of the area;Topography of the area and so on.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>52","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"ANIMAL PRODUCTION : AQUACULTURE","question":"The method of fish preservation in which most of the moisture is lost is","images":[],"options":{"A":"frying","B":"salting","C":"drying","D":"canning"},"answer":"C","explanation":"Drying involves the drying of fish using heat from sun. In this process, fish can only be stored for a short time and the moisture of the fish is lost.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2004>53","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : FACTORS OF PRODUCTION","question":"which of the following statement is not true of agricultural production?","images":[],"options":{"A":"land is an immobile","B":"a fishing ground is a factor of production","C":"human reasources constitute a factor of poduction","D":"availability of land is more important than its quality"},"answer":"D","explanation":"Agricultural production deals with the production of agricultural products for exports and provision of income for the farmers. Availability of land is more important than its quality is not true about Agricultural production.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>54","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : FARM MANAGER","question":"The function or a farm manager include the following except","images":[],"options":{"A":"decision making","B":"coordination of farm activity","C":"supervision of farm labourers","D":"financing agricultural projects"},"answer":"D","explanation":"Farm manager is usually regarded as the entrepreneur whose duties include organisation,administration e.t.c of produce from the farm.Financing agricultural projects is not a function of a farm manager because he or she is not the owner of the farm.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>55","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : PRINCIPLES OF SUPPLY","question":"in the event of increased government subsidies, farmer's production cost","images":[],"options":{"A":"falls, hence supply increase","B":"fall, hence supply decreases","C":"rises, hence supply increase","D":"rises, hence supply decreases"},"answer":"A","explanation":"When the government increased subsides is high, the farmers production cost will fall,hence causing supply to be high this is because the increased government subsides has made farmers produce more supply of goods.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>56","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : PRINCIPLES OF SUPPLY","question":"The curve for unitary elasticity of supply for maize flour is given by","images":["data:image/png;base64,","data:image/png;base64,","data:image/png;base64,","data:image/png;base64,"],"options":{"A":"","B":"","C":"","D":""},"answer":"A","explanation":"Supply is said to be unitary when a change in price leads to an equal change in the quantity of goods supplied. In other words, a 5% change in price will lead to a 5% change in price will lead to a 5% change in supply.","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2004>57","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : PRINCIPLES OF DEMAND","question":"The equilibrum prices of rice is the price at which","images":[],"options":{"A":"its demand exceeds supply","B":"its supply exceed demand","C":"its supply equals demand","D":"consumer cannot buy the quantity they want"},"answer":"C","explanation":"Equilibrium price is that price at which the quantity demanded is equal to the quantity of goods supplied. The point where the demand curve meets the supply curve is called equilibrium position or point.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>58","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : AGRICULTURAL EXTENSION","question":"which of the following activities is not correct about extension agents?","images":[],"options":{"A":"educating farmer on the use of improved techniques","B":"teaching farmers how to plant their crops","C":"training school leavers to become proffessional farmers","D":"teaching farmers how to prepare and apply compost manure."},"answer":"C","explanation":"Extension agents are those people who teach the farmers modern techniques and research findings. They also help in assisting farmers through educational procedures in improving farming methods and techniques","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>59","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : AGRICULTURAL EXTENSION","question":"one of the function of agricultural extension is","images":[],"options":{"A":"cultivation of farmer's farmland","B":"construction of farmers' farmsteads","C":"organisation and coordination of credit sources","D":"running of the country's formal education system"},"answer":"C","explanation":"Agricultural extension is very important for the development of agriculture in West Africa.Its roles or functions include:increase in agricultural production,reaches improved farming practices, assistance to foreign experts, organization and cordination of credit source etc","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2004>60","subject":"Agricultural Science","year":"2004","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : AGRICULTURAL EXTENSION","question":"Why would an extension officer prefer the use of television to the radio when introducing a new technology to farmers?","images":[],"options":{"A":"The extension officer can get immediate feedback","B":"farmer can observe the various steps involved","C":"radio programmes are not reliable and clear enough","D":"it is cheaper to use television than radio"},"answer":"B","explanation":"The extension officer is preferring the use of television to radio when introducing a new technology to farmer is because the use of television is more understanding than that of listened to so he or she will have observed the various steps involved before introducing a new technology to the farmer.","marks":"1","difficulty":"2"}];